member.example:
Bind the LayoutGroup padding property using a serialized binder field — the target LayoutGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LayoutGroupPaddingBinder _padding;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public RectOffset _padding;
    }


Bind the LayoutGroup padding property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LayoutGroup _layoutGroup;
        
        private LayoutGroupPaddingBinder Padding =>
            new(_layoutGroup, PaddingMode.All);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public RectOffset _padding;
    }

Switch the LayoutGroup padding between two values using a serialized binder field — the target LayoutGroup is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private LayoutGroupPaddingSwitcherBinder _isExpanded;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }


Switch the LayoutGroup padding between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private LayoutGroup _layoutGroup;
        [SerializeField] private RectOffset _expandedPadding;
        [SerializeField] private RectOffset _collapsedPadding;
        
        private LayoutGroupPaddingSwitcherBinder IsExpanded => new(
            _layoutGroup, _expandedPadding, _collapsedPadding, PaddingMode.All);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }
